func buildPrompt(workDir string, b *bead.Bead, refs []executeBeadGoverningRef, artifacts *executeBeadArtifacts, baseRev, promptOverride, harness string, contextBudget string) ([]byte, string, error) {
	if strings.TrimSpace(promptOverride) != "" {
		path := promptOverride
		if !filepath.IsAbs(path) {
			path = filepath.Join(workDir, path)
		}
		data, err := readPromptFileBounded(path)
		if err != nil {
			return nil, "", fmt.Errorf("reading prompt override %q: %w", promptOverride, err)
		}
		return data, promptOverride, nil
	}

	var sb strings.Builder
	sb.WriteString("<execute-bead>\n")

	instructions := strings.ReplaceAll(executeBeadInstructionsText(harness), "{{.AttemptDir}}", artifacts.DirRel)
	instructions += executeBeadDynamicStep0Hints(workDir, b)
	// Put the largely static instructions first so prefix caches can reuse as
	// much of the prompt as possible before the bead-specific XML starts.
	fmt.Fprintf(&sb, "  <instructions>\n%s\n  </instructions>\n", xmlEscape(instructions))

	fmt.Fprintf(&sb, "  <bead id=\"%s\">\n", xmlAttrEscape(b.ID))
	fmt.Fprintf(&sb, "    <title>%s</title>\n", xmlEscape(strings.TrimSpace(b.Title)))

	desc := strings.TrimSpace(b.Description)
	if desc == "" {
		sb.WriteString("    <description/>\n")
	} else {
		fmt.Fprintf(&sb, "    <description>\n%s\n    </description>\n", xmlEscape(desc))
	}

	acc := strings.TrimSpace(b.Acceptance)
	if acc == "" {
		sb.WriteString("    <acceptance/>\n")
	} else {
		fmt.Fprintf(&sb, "    <acceptance>\n%s\n    </acceptance>\n", xmlEscape(acc))
	}

	// Bead notes carry review findings from prior iterations, escalation
	// context, or operator hints that did not fit into the description at
	// creation time. Threading them into the prompt as a distinct section
	// lets the agent act on them without the operator having to rewrite the
	// description in place on every reopen.
	if notes := strings.TrimSpace(b.Notes); notes != "" {
		fmt.Fprintf(&sb, "    <notes>\n%s\n    </notes>\n", xmlEscape(notes))
	}

	if len(b.Labels) > 0 {
		fmt.Fprintf(&sb, "    <labels>%s</labels>\n", xmlEscape(strings.Join(b.Labels, ", ")))
	} else {
		sb.WriteString("    <labels/>\n")
	}

	metaAttrs := make([]string, 0, 6)
	if b.Parent != "" {
		metaAttrs = append(metaAttrs, fmt.Sprintf("parent=\"%s\"", xmlAttrEscape(b.Parent)))
	}
	if specID, _ := b.Extra["spec-id"].(string); strings.TrimSpace(specID) != "" {
		metaAttrs = append(metaAttrs, fmt.Sprintf("spec-id=\"%s\"", xmlAttrEscape(strings.TrimSpace(specID))))
	}
	metaAttrs = append(metaAttrs, fmt.Sprintf("base-rev=\"%s\"", xmlAttrEscape(baseRev)))
	metaAttrs = append(metaAttrs, fmt.Sprintf("bundle=\"%s\"", xmlAttrEscape(artifacts.DirRel)))
	fmt.Fprintf(&sb, "    <metadata %s/>\n", strings.Join(metaAttrs, " "))
	sb.WriteString("  </bead>\n")

	// For minimal budget, omit full governing refs and only include bead metadata.
	// This significantly reduces prompt size for cheap-tier attempts on local models.
	if contextBudget == "minimal" {
		sb.WriteString("  <governing>\n    <note>No governing references.</note>\n  </governing>\n")
	} else {
		if len(refs) == 0 {
			fmt.Fprintf(&sb, "  <governing>\n    <note>%s</note>\n  </governing>\n", xmlEscape(executeBeadMissingGoverningText))
		} else {
			sb.WriteString("  <governing>\n")
			for _, ref := range refs {
				attrs := fmt.Sprintf("id=\"%s\" path=\"%s\"", xmlAttrEscape(ref.ID), xmlAttrEscape(ref.Path))
				if strings.TrimSpace(ref.Title) == "" {
					fmt.Fprintf(&sb, "    <ref %s/>\n", attrs)
				} else {
					fmt.Fprintf(&sb, "    <ref %s>%s</ref>\n", attrs, xmlEscape(strings.TrimSpace(ref.Title)))
				}
			}
			sb.WriteString("  </governing>\n")
		}
	}

	sb.WriteString("</execute-bead>\n")

	return []byte(sb.String()), "synthesized", nil
}

const executeBeadLargeDescriptionHintThreshold = 8000
const executeBeadAutoDecompositionDepthCap = 2

func executeBeadDynamicStep0Hints(workDir string, b *bead.Bead) string {
	if b == nil {
		return ""
	}

	var sb strings.Builder
	desc := strings.TrimSpace(b.Description)
	if len(desc) > executeBeadLargeDescriptionHintThreshold {
		fmt.Fprintf(&sb, "\n\n## Large description hint\n")
		fmt.Fprintf(&sb, "This bead description is %d bytes (> %d). Treat Step 0 as a split-first pass and prefer child-bead scoping before implementation.\n",
			len(desc), executeBeadLargeDescriptionHintThreshold)
	}

	depth := beadDecompositionDepth(workDir, b)
	if depth >= executeBeadAutoDecompositionDepthCap {
		fmt.Fprintf(&sb, "\n\n## Decomposition depth cap\n")
		fmt.Fprintf(&sb, "This bead is already at decomposition depth %d. Do not create another child layer; if it is still too large, reject the split with a short explanation and write no_changes_rationale.txt instead.\n",
			depth)
	}

	return sb.String()
}

func beadDecompositionDepth(workDir string, b *bead.Bead) int {
	if b == nil {
		return 0
	}

	store := bead.NewStore(filepath.Join(workDir, ".ddx"))
	depth := 0
	seen := map[string]struct{}{}
	current := b
	for current != nil {
		parentID := strings.TrimSpace(current.Parent)
		if parentID == "" {
			break
		}
		depth++
		if _, ok := seen[parentID]; ok {
			break
		}
		seen[parentID] = struct{}{}
		parent, err := store.Get(parentID)
		if err != nil || parent == nil {
			break
		}
		current = parent
	}
	return depth
}

// promptSHA returns the hex-encoded sha256 of the rendered prompt bytes.
// Used as manifest.prompt_sha so analytics can group attempts by the exact
// prompt that produced them.
func promptSHA(promptContent []byte) string {
	sum := sha256.Sum256(promptContent)
	return hex.EncodeToString(sum[:])
}

func beadMetadata(b *bead.Bead) map[string]any {

package agent

import (
	"os"
	"path/filepath"
	"strings"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// TestExecuteBead_ContextBudgetMinimal verifies that when ContextBudget is
// set to "minimal", the prompt omits large governing refs and only includes
// the bead description, acceptance, and minimal metadata.
func TestExecuteBead_ContextBudgetMinimal(t *testing.T) {
	root := t.TempDir()
	wt := t.TempDir()

	b := &bead.Bead{
		ID:          "ddx-ctx-budget",
		Title:       "Context budget test",
		Description: "Test minimal context budget.",
		Acceptance:  "Prompt is smaller when context-budget=minimal",
		Labels:      []string{"test"},
	}
	refs := []executeBeadGoverningRef{
		{ID: "FEAT-LARGE", Path: "docs/helix/FEAT-SPEC.md", Title: "Large Spec Document"},
	}

	arts, err := createArtifactBundle(root, wt, "20260101T000000-ctx00001")
	if err != nil {
		t.Fatalf("createArtifactBundle: %v", err)
	}

	const baseRev = "1234abcd"

	// Generate prompt without minimal budget (full)
	promptFull, srcFull, err := buildPrompt(root, b, refs, arts, baseRev, "", "claude", "")
	if err != nil {
		t.Fatalf("buildPrompt (full): %v", err)
	}
	if srcFull != "synthesized" {
		t.Errorf("expected prompt source=synthesized, got %q", srcFull)
	}

	// Generate prompt with minimal budget
	promptMinimal, srcMinimal, err := buildPrompt(root, b, refs, arts, baseRev, "", "claude", "minimal")
	if err != nil {
		t.Fatalf("buildPrompt (minimal): %v", err)
	}
	if srcMinimal != "synthesized" {
		t.Errorf("expected prompt source=synthesized, got %q", srcMinimal)
	}

	// The minimal budget prompt should be smaller than the full one
	if len(promptMinimal) >= len(promptFull) {
		t.Errorf("minimal budget prompt (%d bytes) should be smaller than full (%d bytes)", len(promptMinimal), len(promptFull))
	}

	// Both prompts should have the bead description and acceptance
	fullStr := string(promptFull)
	minimalStr := string(promptMinimal)

	for _, s := range []string{fullStr, minimalStr} {
		if !strings.Contains(s, "<description>") || !strings.Contains(s, b.Description) {
			t.Errorf("prompt missing description: %q", s)
		}
		if !strings.Contains(s, "<acceptance>") || !strings.Contains(s, b.Acceptance) {
			t.Errorf("prompt missing acceptance: %q", s)
		}
	}

	// Full prompt should contain governing refs
	if !strings.Contains(fullStr, "<governing>") || !strings.Contains(fullStr, "FEAT-LARGE") {
		t.Errorf("full prompt should contain governing refs")
	}

	// Minimal budget prompt should NOT contain the full governing refs
	minimalHasRefs := strings.Contains(minimalStr, "FEAT-LARGE") || strings.Contains(minimalStr, "<governing>") && !strings.Contains(minimalStr, "No governing references")
	if minimalHasRefs {
		t.Errorf("minimal budget prompt should omit large governing refs, but found references")
	}

	// Minimal budget should have a note that governing refs are omitted
	if !strings.Contains(minimalStr, "No governing references") {
		t.Errorf("minimal budget prompt should indicate no governing refs")
	}

	// Both should have instructions
	for _, s := range []string{fullStr, minimalStr} {
		if !strings.Contains(s, "<instructions>") {
			t.Errorf("prompt missing instructions")
		}
	}
}

// TestExecuteBead_ContextBudgetDefaultBehavior verifies that empty context
// budget (default) produces the same prompt as before.
func TestExecuteBead_ContextBudgetDefaultBehavior(t *testing.T) {
	root := t.TempDir()
	wt := t.TempDir()

	b := &bead.Bead{
		ID:          "ddx-ctx-default",
		Title:       "Default behavior test",
		Description: "Test default context budget.",
		Acceptance:  "Prompt includes full content when no budget is set",
		Labels:      []string{"test"},
	}
	refs := []executeBeadGoverningRef{
		{ID: "FEAT-DEFAULT", Path: "docs/helix/FEAT-TEST.md", Title: "Test Spec"},
	}

	arts, err := createArtifactBundle(root, wt, "20260101T000000-def00001")
	if err != nil {
		t.Fatalf("createArtifactBundle: %v", err)
	}

	const baseRev = "1234abcd"

	// Generate prompt with empty context budget (default)
	prompt, src, err := buildPrompt(root, b, refs, arts, baseRev, "", "claude", "")
	if err != nil {
		t.Fatalf("buildPrompt (default): %v", err)
	}
	if src != "synthesized" {
		t.Errorf("expected prompt source=synthesized, got %q", src)
	}

	s := string(prompt)

	// Should include description and acceptance
	if !strings.Contains(s, b.Description) {
		t.Errorf("default prompt should include description")
	}
	if !strings.Contains(s, b.Acceptance) {
		t.Errorf("default prompt should include acceptance")
	}

	// Should include governing refs
	if !strings.Contains(s, "FEAT-DEFAULT") {
		t.Errorf("default prompt should include governing refs")
	}
	if !strings.Contains(s, "<governing>") {
		t.Errorf("default prompt should have <governing> section")
	}

	// Should include missing governing text when refs empty
	arts2, err := createArtifactBundle(root, wt, "20260101T000000-def00002")
	if err != nil {
		t.Fatalf("createArtifactBundle: %v", err)
	}
	prompt2, _, err := buildPrompt(root, b, []executeBeadGoverningRef{}, arts2, baseRev, "", "claude", "")
	if err != nil {
		t.Fatalf("buildPrompt (no refs): %v", err)
	}
	if !strings.Contains(string(prompt2), executeBeadMissingGoverningText) {
		t.Errorf("prompt with no refs should include missing governing text")
	}
}

// TestExecuteBead_ContextBudgetEmptyRefsWithMinimal verifies that minimal
// budget with empty refs produces a consistent prompt.
func TestExecuteBead_ContextBudgetEmptyRefsWithMinimal(t *testing.T) {
	root := t.TempDir()
	wt := t.TempDir()

	b := &bead.Bead{
		ID:          "ddx-ctx-empty-min",
		Title:       "Empty refs minimal test",
		Description: "No governing refs with minimal budget.",
		Acceptance:  "Minimal budget works with empty refs",
		Labels:      []string{"test"},
	}

	arts, err := createArtifactBundle(root, wt, "20260101T000000-empty00001")
	if err != nil {
		t.Fatalf("createArtifactBundle: %v", err)
	}

	const baseRev = "1234abcd"

	// Generate prompt with empty refs and minimal budget
	prompt, src, err := buildPrompt(root, b, []executeBeadGoverningRef{}, arts, baseRev, "", "claude", "minimal")
	if err != nil {
		t.Fatalf("buildPrompt (empty refs minimal): %v", err)
	}
	if src != "synthesized" {
		t.Errorf("expected prompt source=synthesized, got %q", src)
	}

	s := string(prompt)

	// Should include description and acceptance
	if !strings.Contains(s, b.Description) {
		t.Errorf("prompt should include description")
	}
	if !strings.Contains(s, b.Acceptance) {
		t.Errorf("prompt should include acceptance")
	}

	// Should have minimal governing note, not missing refs text
	if strings.Contains(s, executeBeadMissingGoverningText) {
		t.Errorf("minimal budget should not use missing refs text")
	}
	if !strings.Contains(s, "No governing references") {
		t.Errorf("minimal budget should have its own note")
	}
}

// TestExecuteBead_ContextBudgetOmitSpecDoc verifies that when spec-id is set
// but context-budget=minimal, the full spec document content is not included.
func TestExecuteBead_ContextBudgetOmitSpecDoc(t *testing.T) {
	root := t.TempDir()
	wt := t.TempDir()

	// Create a spec document that would normally be included
	specPath := filepath.Join(wt, "docs", "helix", "FEAT-TEST.md")
	if err := os.MkdirAll(filepath.Dir(specPath), 0o755); err != nil {
		t.Fatal(err)
	}
	specContent := `# FEAT-TEST Test Specification

This is a large specification document with many details that we want to omit
for cheap-tier attempts with minimal context budget.
`
	if err := os.WriteFile(specPath, []byte(specContent), 0o644); err != nil {
		t.Fatal(err)
	}

	b := &bead.Bead{
		ID:          "ddx-ctx-spec",
		Title:       "Spec test with minimal budget",
		Description: "Test spec-id inclusion.",
		Acceptance:  "Spec content omitted with minimal budget",
		Labels:      []string{"test"},
	}
	b.Extra = map[string]any{"spec-id": "FEAT-TEST"}

	arts, err := createArtifactBundle(root, wt, "20260101T000000-spec00001")
	if err != nil {
		t.Fatalf("createArtifactBundle: %v", err)
	}

	const baseRev = "1234abcd"

	// Full prompt (should resolve spec)
	promptFull, _, err := buildPrompt(root, b, []executeBeadGoverningRef{}, arts, baseRev, "", "claude", "")
	if err != nil {
		t.Fatalf("buildPrompt (full): %v", err)
	}

	// Minimal prompt (should NOT include spec content)
	promptMinimal, _, err := buildPrompt(root, b, []executeBeadGoverningRef{}, arts, baseRev, "", "claude", "minimal")
	if err != nil {
		t.Fatalf("buildPrompt (minimal): %v", err)
	}

	fullStr := string(promptFull)
	minimalStr := string(promptMinimal)

	minimalStr := string(promptMinimal)

	// Check that minimal is smaller
	if len(minimalStr) >= len(fullStr) {
		t.Errorf("minimal budget prompt (%d bytes) should be smaller than full (%d bytes)", len(minimalStr), len(fullStr))
	}

	// Both should have the spec-id metadata
	if !strings.Contains(minimalStr, "FEAT-TEST") {
		t.Errorf("prompt should include spec-id in metadata")
	}

	// Full prompt may or may not include the spec content (depends on ref resolution)
	// but minimal should definitely NOT include it
	if strings.Contains(minimalStr, "large specification document") {
		t.Errorf("minimal budget prompt should not include spec content")
	}
}

func TestExecuteBead_LargeDescriptionGetsStep0Hint(t *testing.T) {
	root := t.TempDir()
	wt := t.TempDir()

	b := &bead.Bead{
		ID:          "ddx-large-desc",
		Title:       "Large description test",
		Description: strings.Repeat("x", executeBeadLargeDescriptionHintThreshold+1),
		Acceptance:  "Large descriptions trigger the Step 0 hint",
		Labels:      []string{"test"},
	}

	arts, err := createArtifactBundle(root, wt, "20260101T000000-large0001")
	if err != nil {
		t.Fatalf("createArtifactBundle: %v", err)
	}

	prompt, _, err := buildPrompt(root, b, nil, arts, "1234abcd", "", "claude", "")
	if err != nil {
		t.Fatalf("buildPrompt: %v", err)
	}

	s := string(prompt)
	if !strings.Contains(s, "Large description hint") {
		t.Fatalf("prompt missing large-description hint: %s", s)
	}
	if !strings.Contains(s, "split-first pass") {
		t.Fatalf("prompt missing split-first hint: %s", s)
	}
	if !strings.Contains(s, "8001 bytes") {
		t.Fatalf("prompt missing concrete large-description byte count: %s", s)
	}
}

func TestExecuteBead_ThirdLevelDecompositionGetsRejectedWithExplanation(t *testing.T) {
	root := t.TempDir()
	wt := t.TempDir()
	ddxDir := filepath.Join(root, ".ddx")
	if err := os.MkdirAll(ddxDir, 0o755); err != nil {
		t.Fatal(err)
	}
	store := bead.NewStore(ddxDir)
	if err := store.Init(); err != nil {
		t.Fatal(err)
	}

	rootBead := &bead.Bead{
		ID:    "ddx-root",
		Title: "Root bead",
	}
	childBead := &bead.Bead{
		ID:     "ddx-child",
		Title:  "Child bead",
		Parent: rootBead.ID,
	}
	grandchildBead := &bead.Bead{
		ID:     "ddx-grandchild",
		Title:  "Grandchild bead",
		Parent: childBead.ID,
	}
	for _, b := range []*bead.Bead{rootBead, childBead, grandchildBead} {
		if err := store.Create(b); err != nil {
			t.Fatalf("store.Create(%s): %v", b.ID, err)
		}
	}

	arts, err := createArtifactBundle(root, wt, "20260101T000000-depth0001")
	if err != nil {
		t.Fatalf("createArtifactBundle: %v", err)
	}

	cases := []struct {
		name    string
		bead    *bead.Bead
		wantCap bool
	}{
		{name: "root", bead: rootBead, wantCap: false},
		{name: "child", bead: childBead, wantCap: false},
		{name: "grandchild", bead: grandchildBead, wantCap: true},
	}

	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			prompt, _, err := buildPrompt(root, tc.bead, nil, arts, "1234abcd", "", "claude", "")
			if err != nil {
				t.Fatalf("buildPrompt: %v", err)
			}
			s := string(prompt)
			gotCap := strings.Contains(s, "Decomposition depth cap")
			if gotCap != tc.wantCap {
				t.Fatalf("cap hint presence = %v, want %v; prompt=%s", gotCap, tc.wantCap, s)
			}
			if tc.wantCap {
				if !strings.Contains(s, "already at decomposition depth 2") {
					t.Fatalf("grandchild prompt missing explicit depth explanation: %s", s)
				}
				if !strings.Contains(s, "reject the split") {
					t.Fatalf("grandchild prompt missing rejection guidance: %s", s)
				}
				if !strings.Contains(s, "no_changes_rationale.txt") {
					t.Fatalf("grandchild prompt missing no_changes rationale guidance: %s", s)
				}
			}
		})
	}
}
